import { execution } from '@dynatrace-sdk/automation-utils';

const TASK_ID = 'predict_disk_capacity';

// 2 GiB in bytes
const THRESHOLD_BYTES = 2n * 1024n * 1024n * 1024n; // 2147483648

// Choose which forecast series to evaluate: "upper" (recommended), "point", or "lower"
const SERIES_TO_CHECK = 'upper';

function toGiB(bytesNumber) {
  return bytesNumber / (1024 ** 3);
}

function parseIntervalNs(interval) {
  // interval comes as a string like "180000000000" (ns)
  try {
    return BigInt(interval);
  } catch {
    return null;
  }
}

function addMs(isoStart, ms) {
  return new Date(new Date(isoStart).getTime() + ms).toISOString();
}

function scanSeries(values, thresholdBigInt) {
  let max = -Infinity;
  let firstIdx = -1;
  let firstVal = null;

  for (let i = 0; i < (values?.length ?? 0); i++) {
    const v = values[i];
    if (typeof v === 'number' && Number.isFinite(v)) {
      if (v > max) max = v;
      if (firstIdx < 0 && BigInt(Math.trunc(v)) >= thresholdBigInt) {
        firstIdx = i;
        firstVal = v;
      }
    }
  }

  return { max, firstIdx, firstVal };
}

function pickForecastRecord(item) {
  // Your payload has: item.timeSeriesDataWithPredictions.records[0]
  // Use first record; adjust if you ever have multiple records per item.
  return item?.timeSeriesDataWithPredictions?.records?.[0] ?? null;
}

function extractIdentity(item, rec) {
  // Prefer the prediction record fields; fallback to analyzedTimeSeriesQuery fields.
  const analyzedRec = item?.analyzedTimeSeriesQuery?.expression?.records?.[0] ?? {};

  return {
    cluster:
      rec?.['k8s.cluster.name'] ??
      analyzedRec?.['k8s.cluster.name'] ??
      'unknown-cluster',
    pvc:
      rec?.['k8s.persistent_volume_claim.name'] ??
      analyzedRec?.['k8s.persistent_volume_claim.name'] ??
      'unknown-pvc',
  };
}

export default async function ({ execution_id }) {
  const exe = await execution(execution_id);

  const predResult = await exe.result(TASK_ID);
  // In your snippet you did: const result = predResult['result'];
  // Here we handle both shapes gracefully:
  const payload = predResult?.result ?? predResult;
  const outputs = payload?.output ?? [];

  const breaches = [];

  for (const item of outputs) {
    const rec = pickForecastRecord(item);
    if (!rec) continue;

    const { cluster, pvc } = extractIdentity(item, rec);

    const series =
      (SERIES_TO_CHECK === 'upper' && rec?.['dt.davis.forecast:upper']) ||
      (SERIES_TO_CHECK === 'point' && rec?.['dt.davis.forecast:point']) ||
      (SERIES_TO_CHECK === 'lower' && rec?.['dt.davis.forecast:lower']) ||
      // fallback preference order
      rec?.['dt.davis.forecast:upper'] ||
      rec?.['dt.davis.forecast:point'] ||
      rec?.['dt.davis.forecast:lower'] ||
      [];

    const { max, firstIdx, firstVal } = scanSeries(series, THRESHOLD_BYTES);

    const start = rec?.timeframe?.start; // e.g. "2026-03-04T00:33Z"
    const intervalNs = parseIntervalNs(rec?.interval);
    const intervalMs = intervalNs ? Number(intervalNs / 1_000_000n) : null;

    const firstCrossingTime =
      firstIdx >= 0 && start && intervalMs != null
        ? addMs(start, firstIdx * intervalMs)
        : null;

    if (firstIdx >= 0) {
      breaches.push({
        cluster,
        pvc,
        analysisStatus: item?.analysisStatus,
        forecastQualityAssessment: item?.forecastQualityAssessment,
        checkedSeries:
          series === rec?.['dt.davis.forecast:upper']
            ? 'dt.davis.forecast:upper'
            : series === rec?.['dt.davis.forecast:point']
              ? 'dt.davis.forecast:point'
              : series === rec?.['dt.davis.forecast:lower']
                ? 'dt.davis.forecast:lower'
                : 'fallback',
        thresholdBytes: Number(THRESHOLD_BYTES),
        thresholdGiB: 2,
        firstCrossing: {
          index: firstIdx,
          time: firstCrossingTime,
          valueBytes: firstVal,
          valueGiB: firstVal != null ? toGiB(firstVal) : null,
        },
        maxForecast: {
          valueBytes: max,
          valueGiB: Number.isFinite(max) ? toGiB(max) : null,
        },
      });
    }
  }

  const summary = {
    thresholdBytes: Number(THRESHOLD_BYTES),
    thresholdGiB: 2,
    checkedSeriesPreference: SERIES_TO_CHECK,
    totalSeries: outputs.length,
    breachCount: breaches.length,
    okCount: outputs.length - breaches.length,
    breaches,
  };

  console.log(JSON.stringify(summary, null, 2));

  // OPTIONAL: Fail the workflow if any series breaches the threshold
  // if (breaches.length > 0) {
  //   throw new Error(`Forecast exceeds 2GiB for ${breaches.length} series`);
  // }

  return summary;
}

import { execution } from '@dynatrace-sdk/automation-utils';

const TASK_ID = 'predict_disk_capacity';
const THRESHOLD = 2 * 1024 * 1024 * 1024; // 2GiB in bytes

export default async function ({ execution_id }) {
  const exe = await execution(execution_id);
  const predResult = await exe.result(TASK_ID);
  const result = predResult.result;

  for (const item of result.output) {
    const rec = item.timeSeriesDataWithPredictions.records[0];
    const series = rec['dt.davis.forecast:upper'] || rec['dt.davis.forecast:point'];

    for (const v of series) {
      if (v != null && v >= THRESHOLD) return true;
    }
  }

  return false;
}
